<div class="col-md-4"><div class="form-check form-switch"><input class="form-check-input" type="checkbox" name="enabled" id="etaEnabled" <?=!empty($settings['enabled'])?'checked':''?>><label class="form-check-label" for="etaEnabled">Enable ETA processing</label></div></div>
