<div class="col-md-4"><div class="form-check form-switch"><input class="form-check-input" type="checkbox" name="send_delay_notices" id="etaDelay" <?=!empty($settings['send_delay_notices'])?'checked':''?>><label class="form-check-label" for="etaDelay">Send delay notices</label></div></div>
